   108	static int
   109	eval_arrlen(Expr* expr)
   110	{
   111	  if (auto p = expr->dcst<IntegerLiteral>())
   112	    return p->val;
   113	
   114	  if (auto p = expr->dcst<DeclRefExpr>()) {
   115	    if (p->decl == nullptr)
