   117	
   118	    auto var = p->decl->dcst<VarDecl>();
   119	    if (!var || !var->type->qual.const_)
   120	      ABORT(); // 数组长度必须是编译期常量
   121	
   122	    switch (var->type->spec) {
   123	      case Type::Spec::kChar:
   124	      case Type::Spec::kInt:
   125	      case Type::Spec::kLong:
   126	      case Type::Spec::kLongLong:
   127	        return eval_arrlen(var->init);
   128	
   129	      default:
   130	        ABORT(); // 长度表达式必须是数值类型
   131	    }
   132	  }
   133	
   134	  if (auto p = expr->dcst<UnaryExpr>()) {
   135	    auto sub = eval_arrlen(p->sub);
   136	
   137	    switch (p->op) {
   138	      case UnaryExpr::kPos:
   139	        return sub;
   140	
   141	      case UnaryExpr::kNeg:
   142	        return -sub;
   143	
   144	      default:
   145	        ABORT();
   146	    }
   147	  }
   148	
   149	  if (auto p = expr->dcst<BinaryExpr>()) {
   150	    auto lft = eval_arrlen(p->lft);
   151	    auto rht = eval_arrlen(p->rht);
   152	
   153	    switch (p->op) {
   154	      case BinaryExpr::kAdd:
   155	        return lft + rht;
   156	
   157	      case BinaryExpr::kSub:
   158	        return lft - rht;
   159	
   160	      default:
   161	        ABORT();
   162	    }
   163	  }
   164	
   165	  if (auto p = expr->dcst<InitListExpr>()) {
   166	    if (p->list.empty())
   167	      return 0;
   168	    return eval_arrlen(p->list[0]);
   169	  }
   170	
   171	  ABORT();
   172	}
